  1	import * as React from 'react';
  2	import { cephStorageLabel } from '@odf/core/constants';
  3	import { useODFNamespaceSelector } from '@odf/core/redux';
  4	import { nodeResource } from '@odf/core/resources';
  5	import { StorageEfficiencyContent } from '@odf/ocs/dashboards/persistent-internal/storage-efficiency-card/storage-efficiency-card';
  6	import { DATA_RESILIENCY_QUERY, StorageDashboardQuery } from '@odf/ocs/queries';
  7	import { getCephNodes, getDataResiliencyState } from '@odf/ocs/utils';
  8	import {
  9	  DASH,
 10	  DEFAULT_INFRASTRUCTURE,
 11	  ODF_OPERATOR,
 12	} from '@odf/shared/constants';
 13	import { SectionHeading } from '@odf/shared/heading/page-heading';
 14	import {
 15	  useCustomPrometheusPoll,
 16	  usePrometheusBasePath,
 17	} from '@odf/shared/hooks/custom-prometheus-poll';
 18	import { useK8sGet } from '@odf/shared/hooks/k8s-get-hook';
 19	import { useFetchCsv } from '@odf/shared/hooks/use-fetch-csv';
 20	import {
 21	  ClusterServiceVersionModel,
 22	  InfrastructureModel,
 23	  NodeModel,
 24	} from '@odf/shared/models';
 25	import { getName } from '@odf/shared/selectors';
 26	import { getNodeStatusGroups } from '@odf/shared/status/Inventory';
 27	import { resourceStatus } from '@odf/shared/status/Resource';
 28	import { Status } from '@odf/shared/status/Status';
 29	import { InfrastructureKind, NodeKind } from '@odf/shared/types';
 30	import { StorageClusterKind } from '@odf/shared/types';
 31	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 32	import { getOprVersionFromCSV } from '@odf/shared/utils';
 33	import {
 34	  resourcePathFromModel,
 35	  getInfrastructurePlatform,
 36	} from '@odf/shared/utils';
 37	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 38	import {
 39	  HealthItem,
 40	  ResourceInventoryItem,
 41	} from '@openshift-console/dynamic-plugin-sdk-internal';
 42	import * as _ from 'lodash-es';
 43	import { Link } from 'react-router-dom-v5-compat';
 44	import {
 45	  DescriptionList,
 46	  DescriptionListDescription,
 47	  DescriptionListGroup,
 48	  DescriptionListTerm,
 49	} from '@patternfly/react-core';
 50	
 51	const resiliencyProgressQuery = (managedByOCS: string) =>
 52	  DATA_RESILIENCY_QUERY(managedByOCS)[
 53	    StorageDashboardQuery.RESILIENCY_PROGRESS
 54	  ];
 55	
 56	export type StorageClusterDetailsProps = {
 57	  resource: StorageClusterKind;
 58	};
 59	
 60	export const StorageClusterDetails: React.FC<StorageClusterDetailsProps> = ({
 61	  resource: storageCluster,
 62	}) => {
 63	  const { t } = useCustomTranslation();
 64	
 65	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
 66	
 67	  const [infrastructure, infrastructureLoaded, infrastructureError] =
 68	    useK8sGet<InfrastructureKind>(InfrastructureModel, DEFAULT_INFRASTRUCTURE);
 69	
 70	  const ocsName = getName(storageCluster);
 71	  const infrastructurePlatform =
 72	    infrastructureLoaded && _.isEmpty(infrastructureError)
 73	      ? getInfrastructurePlatform(infrastructure)
 74	      : DASH;
 75	
 76	  const [resiliencyProgress, resiliencyProgressError] = useCustomPrometheusPoll(
 77	    {
 78	      query: resiliencyProgressQuery(ocsName),
 79	      endpoint: 'api/v1/query' as any,
 80	      basePath: usePrometheusBasePath(),
 81	    }
 82	  );
 83	  const dataResiliencyState = getDataResiliencyState(
 84	    [{ response: resiliencyProgress, error: resiliencyProgressError }],
 85	    t
 86	  );
 87	
 88	  // Topology is only supported for Internal mode
 89	  const mode = t('Internal');
 90	
 91	  const [csv, csvLoaded, csvError] = useFetchCsv({
 92	    specName: ODF_OPERATOR,
 93	    namespace: odfNamespace,
 94	    startPollingInstantly: isNsSafe,
 95	  });
 96	  const serviceVersion =
 97	    csvLoaded && _.isEmpty(csvError) ? getOprVersionFromCSV(csv) : DASH;
 98	  const servicePath = `${resourcePathFromModel(
 99	    ClusterServiceVersionModel,
100	    getName(csv),
101	    odfNamespace
102	  )}`;
103	  const serviceName = t('Data Foundation');
104	
105	  const [nodesData, nodesLoaded, nodesLoadError] =
106	    useK8sWatchResource<NodeKind[]>(nodeResource);
107	  const storageLabel = cephStorageLabel(odfNamespace);
108	  const ocsNodesHref = `/search?kind=${NodeModel.kind}&q=${storageLabel}`;
109	
110	  return (
111	    <div className="odf-m-pane__body">
112	      <SectionHeading text={t('Cluster details')} />
113	      <div className="row">
114	        <div className="col-md-5 col-xs-12">
115	          <DescriptionList>
116	            <DescriptionListGroup>
117	              <DescriptionListTerm>{t('Name')}</DescriptionListTerm>
118	              <DescriptionListDescription>
119	                {ocsName || DASH}
120	              </DescriptionListDescription>
121	            </DescriptionListGroup>
122	
123	            <DescriptionListGroup>
124	              <DescriptionListTerm>{t('Data resiliency')}</DescriptionListTerm>
125	              <DescriptionListDescription>
126	                {' '}
127	                <HealthItem
128	                  title=""
129	                  state={dataResiliencyState.state}
130	                  details={dataResiliencyState.message}
131	                />
132	              </DescriptionListDescription>
133	            </DescriptionListGroup>
134	
135	            <DescriptionListGroup>
136	              <DescriptionListTerm>{t('Provider')}</DescriptionListTerm>
137	              <DescriptionListDescription>
138	                {infrastructurePlatform}
139	              </DescriptionListDescription>
140	            </DescriptionListGroup>
141	
142	            <DescriptionListGroup>
143	              <DescriptionListTerm>{t('Mode')}</DescriptionListTerm>
144	              <DescriptionListDescription>{mode}</DescriptionListDescription>
145	            </DescriptionListGroup>
146	
147	            <DescriptionListGroup>
148	              <DescriptionListTerm>{t('Version')}</DescriptionListTerm>
149	              <DescriptionListDescription>
150	                {serviceVersion}
151	              </DescriptionListDescription>
152	            </DescriptionListGroup>
153	
154	            <DescriptionListGroup>
155	              <DescriptionListTerm>{t('Inventory')}</DescriptionListTerm>
156	              <DescriptionListDescription>
157	                <ResourceInventoryItem
158	                  dataTest="inventory-nodes"
159	                  isLoading={!nodesLoaded}
160	                  error={!!nodesLoadError}
161	                  kind={NodeModel as any}
162	                  resources={getCephNodes(nodesData, odfNamespace)}
163	                  mapper={getNodeStatusGroups}
164	                  basePath={ocsNodesHref}
165	                />
166	              </DescriptionListDescription>
167	            </DescriptionListGroup>
168	          </DescriptionList>
169	        </div>
170	        <div className="col-md-7 col-xs-12">
171	          <DescriptionList>
172	            <DescriptionListGroup>
173	              <DescriptionListTerm>{t('Status')}</DescriptionListTerm>
174	              <DescriptionListDescription>
175	                <Status status={resourceStatus(storageCluster)} />
176	              </DescriptionListDescription>
177	            </DescriptionListGroup>
178	
179	            <DescriptionListGroup>
180	              <DescriptionListTerm>{t('Service name')}</DescriptionListTerm>
181	              <DescriptionListDescription className="text-capitalize">
182	                {isNsSafe && csvLoaded && !csvError ? (
183	                  <Link data-test="ocs-link" to={servicePath}>
184	                    {serviceName}
185	                  </Link>
186	                ) : (
187	                  serviceName
188	                )}
189	              </DescriptionListDescription>
190	            </DescriptionListGroup>
191	
192	            <DescriptionListGroup>
193	              <DescriptionListTerm>
194	                {t('Storage efficiency')}
195	              </DescriptionListTerm>
196	              <DescriptionListDescription>
197	                <StorageEfficiencyContent />
198	              </DescriptionListDescription>
199	            </DescriptionListGroup>
200	          </DescriptionList>
201	        </div>
202	      </div>
203	    </div>
204	  );
205	};

